const FILTER_TYPES={SERIES_ID:'seriesid',NOT:'not-',AND:'and-',OR:'or-',STARTS_WITH:'startsWith-',CONTAINS:'contains-',MATCHES:'matches-',COUNTRY:'country-',ATHLETE:'athlete',WITHIN:'within-',COMPASS:'compass',CLOSEST:'closest',RANDOM:'random',NONE:'none',ALL:'all',PIN:'pin-'};const MARKER_ICON_URL='https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-';const MARKER_SHADOW_URL='https://cdnjs.cloudflare.com/ajax/libs/leaflet/0.7.7/images/marker-shadow.png';const EVENTS_API_URL='https://snowy-wood-82b6.dave-sowerby.workers.dev/events';var mymap;var markerGroup;var options;var athleteData=[];var filters=[];var position;var hamburger;var withinFilter;var closestFilter;var events;var initialized=false;var $events;var countries;var markerIconCache={};function parseName(nameevent){return(typeof(nameevent)!=='undefined')?nameevent.properties.EventShortName:undefined;}
function parseLongName(nameevent){return(typeof(nameevent)!=='undefined')?nameevent.properties.EventLongName:undefined;}
function parseEventId(eventidevent){return(typeof(eventidevent)!=='undefined')?eventidevent.properties.eventname:undefined;}
function parseLongitude(longevent){return(typeof(longevent)!=='undefined')?parseFloat(longevent.geometry.coordinates[0]):undefined;}
function parseLatitude(latevent){return(typeof(latevent)!=='undefined')?parseFloat(latevent.geometry.coordinates[1]):undefined;}
function parseCountrycode(countrycodeevent){return(typeof(countrycodeevent)!=='undefined')?countrycodeevent.properties.countrycode:undefined;}
function parseEventUrl(urlevent){var eventid=parseEventId(urlevent);var countrycode=parseCountrycode(urlevent);var country=countries[countrycode];return"//"+country.url+"/"+eventid;}
function parseSeriesId(seriesidevent){return seriesidevent.properties.seriesid;}
$(document).ready(function(){initOptions();initMap();initBurger();centreMap();if(!initialized){initialized=true;initAndLoad();}});navigator.geolocation.getCurrentPosition(function(data){position=data;handleGeolocationComplete();},function(error){console.info("Geolocation error: "+error.message);handleGeolocationComplete();});function handleGeolocationComplete(){if(!initialized){initialized=true;initAndLoad();}else{load();}}
function initOptions(){options=JSON.parse(Cookies.get('options')||'{}');}
function initBurger(){hamburger={navToggle:document.querySelector('.nav-toggle'),nav:document.querySelector('.nav'),doToggle:function(e){e.preventDefault();this.navToggle.classList.toggle('expanded');this.nav.classList.toggle('expanded');},show:function(){this.navToggle.classList.add('expanded');this.nav.classList.add('expanded');},hide:function(){this.navToggle.classList.remove('expanded');this.nav.classList.remove('expanded');}};hamburger.navToggle.addEventListener('click',function(e){hamburger.doToggle(e);});}
function initMap(){mymap=L.map('mapid',{fullscreenControl:true,fullscreenControlOptions:{position:'topright'},zoomControl:false,maxBounds:new L.LatLngBounds(new L.LatLng(-90,-180),new L.LatLng(90,180)),minZoom:2,});L.control.zoom({position:'topright'}).addTo(mymap);markerGroup=L.featureGroup().addTo(mymap);L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{maxZoom:19,attribution:'&copy; <a href="http://www.openstreetmap.org/copyright">OpenStreetMap</a>'}).addTo(mymap);mymap.on('contextmenu',function(eventData){window.location.hash='#closest-5-'+eventData.latlng.lat+','+eventData.latlng.lng;});}
function centreMap(){if(position){mymap.fitBounds([[position.coords.latitude-0.01,position.coords.longitude-0.01],[position.coords.latitude+0.01,position.coords.longitude+0.01]]);}else{mymap.fitBounds([[49.095026,-7.742293],[60.258081000000004,1.847338]]);}}
function showLoading(){$('#mapid').css('opacity','0.5').css('pointer-events','none');}
function hideLoading(){$('#mapid').css('opacity','1').css('pointer-events','auto');}
function displayEvents(filterFunctions){if(filterFunctions.length==0){return;}
showLoading();var displayedEvents=0;var eventList=$events.features;console.info('initial size: '+eventList.length);console.info('processing with '+filterFunctions.length+' filters');for(var i=0;i<filterFunctions.length;i++){var filterFunction=filterFunctions[i];eventList=filterFunction(eventList);console.info('after filter '+i+' there are '+eventList.length+' events');}
console.info('after all filters there are '+eventList.length+' events');window.events=eventList;for(var e=0;e<eventList.length;e++){var event=eventList[e];var longitude=parseLongitude(event);var latitude=parseLatitude(event);var name=parseName(event);addMarker(latitude,longitude,name,'blue',event);displayedEvents++;}
if(displayedEvents>0){mymap.fitBounds(markerGroup.getBounds());hamburger.hide();console.info(displayedEvents+' events displayed');}else{hamburger.show();console.info('no events displayed');}
hideLoading();}
function getMarkerIcon(colour){if(!markerIconCache[colour]){markerIconCache[colour]=L.icon({iconUrl:MARKER_ICON_URL+colour+'.png',shadowUrl:MARKER_SHADOW_URL,iconSize:[25,41],iconAnchor:[12,41],popupAnchor:[1,-34],shadowSize:[41,41]});}
return markerIconCache[colour];}
function addMarker(latitude,longitude,name,iconColour,$event){var marker=L.marker([latitude,longitude],{icon:getMarkerIcon(iconColour)});var markerContent;if(typeof($event)!=='undefined'){var eventUrl=parseEventUrl($event);markerContent='<strong><a target="_blank" href="'+eventUrl+'/">'+name+'</a></strong><br />';markerContent+='<a target="_blank" href="'+eventUrl+'/course/">Course page</a><br />';markerContent+='<a target="_blank" href="'+eventUrl+'/futureroster/">Future Roster</a><br />';markerContent+='<a target="_blank" href="'+eventUrl+'/results/eventhistory/">Event History</a><br />';markerContent+='<a target="_blank" href="https://www.facebook.com/search/top/?q='+encodeURIComponent(name)+'%20parkrun&epa=SEARCH_BOX">Facebook</a><br />';markerContent+='<a target="_blank" href="https://www.youtube.com/results?search_query='+encodeURIComponent(name)+'%20parkrun">YouTube</a>';}else if(typeof(name)!=='undefined'){markerContent=name;}
markerContent+='<br /><a target="_blank" href="https://www.google.com/maps/dir/?api=1&destination='+latitude+','+longitude+'">Directions</a><br />';markerContent+='<a target="_blank" href="./weather#'+latitude+','+longitude+'">Weather Forecast</a><br />';markerContent+='<a target="_blank" href="https://www.happycow.net/searchmap?lat='+latitude+'&lng='+longitude+'&vegan=true">Local vegan food</a><br />';markerContent+='<a target="_blank" href="https://www.nationaltrust.org.uk/search?type=place&lat='+latitude+'&lon='+longitude+'&view=map">National Trust venues</a><br />';markerContent+='<a target="_blank" href="https://www.nationaltrust.org.uk/search?type=place&lat='+latitude+'&lon='+longitude+'&filter=houses-and-buildings&view=map">National Trust houses</a><br />';markerContent+='<a target="_blank" href="https://www.premierinn.com/gb/en/search.html?&LOCATION='+latitude+','+longitude+'">Local Premier Inns</a><br />';markerContent+='<a target="_blank" href="https://www.pitchup.com/search/?sort=&lat='+latitude+'&lng='+longitude+'&facet=toilet-block&facet=adults-only&facet=shower-available&within=40&q=&type=4&adults=2&children=0">Tent site</a>';marker.bindPopup(markerContent);marker.addTo(markerGroup);}
function filterEvents(eventList,eventFilter){return function(events){var filteredEvents=[];for(var e=0;e<events.length;e++){var event=events[e];if(eventFilter(event)){filteredEvents.push(event);}}
return filteredEvents;}}
function createSeriesIdFilter(seriesid){return filterEvents(events,function(event){return parseSeriesId(event)==seriesid;});}
function createNotFilter(innerFilter){var filterFunction=getFilter(innerFilter);return function(events){var includedEvents=filterFunction(events);return _.differenceWith(events,includedEvents,function(event1,event2){return parseEventId(event1)==parseEventId(event2);});};}
function createAndFilter(andFilterStr){var andFilters=[];andFilterStr.split('&&').filter(function(e){return e}).forEach(function(andFilterPart){andFilters.push(getFilter(andFilterPart));});return function(events){var filteredEvents=events;for(var i=0;i<andFilters.length;i++){filteredEvents=andFilters[i](filteredEvents);}
return filteredEvents;}}
function createOrFilter(orFilterStr){var orFilters=[];orFilterStr.split('||').filter(function(e){return e}).forEach(function(orFilterPart){orFilters.push(getFilter(orFilterPart));});return function(events){orFilterResults=[];for(var i=0;i<orFilters.length;i++){orFilterResults=_.union(orFilterResults,orFilters[i](events));}
return orFilterResults;}}
function createStartsWithFilter(prefix){return filterEvents(events,function(event){var name=parseName(event);return name.toLowerCase().startsWith(prefix.toLowerCase())||name.toLowerCase().startsWith('parkrun '+prefix.toLowerCase());});}
function createContainsFilter(needle){return filterEvents(events,function(event){var name=parseName(event);return name.toLowerCase().indexOf(needle.toLowerCase())>-1;});}
function createMatchesFilter(regexStr){var regex=new RegExp(regexStr,'i');return filterEvents(events,function(event){var shortName=parseName(event);var longName=parseLongName(event);return regex.test(shortName.toLowerCase())||regex.test(longName.toLowerCase());});}
function createCountryFilter(country){var countryCodeMap={'austria':4,'at':4,'australia':3,'au':3,'canada':14,'ca':14,'denmark':23,'dk':23,'finland':30,'fi':30,'france':31,'fr':31,'germany':32,'de':32,'ireland':42,'ie':42,'italy':44,'it':44,'japan':46,'ja':46,'lithuania':54,'lt':54,'malaysia':57,'my':57,'netherlands':64,'nl':64,'new-zealand':65,'new zealand':65,'nz':65,'norway':67,'no':67,'poland':74,'pl':74,'russia':79,'ru':79,'singapore':82,'sg':82,'south africa':85,'south-africa':85,'za':85,'sweden':88,'se':88,'united kingdom':97,'united-kingdom':97,'uk':97,'united states':98,'united-states':98,'usa':98,'us':98};var countrycode=countryCodeMap[country.toLowerCase()];return filterEvents(events,function(countryEvent){return countrycode===parseCountrycode(countryEvent);});}
function createAthleteFilter(athleteId){if(athleteId=='athlete'){athleteId=options.athleteId;}else{athleteId=athleteId.trim();if(athleteId.toUpperCase().startsWith('A')){athleteId=athleteId.substring(1);}}
if(typeof(athleteData[athleteId])==='undefined'){$.ajax({url:'./athletes/'+athleteId+'.json',dataType:'json'}).done(function(data){athleteData[athleteId]=data;}).fail(function(){console.error('Failed to load athlete data for '+athleteId);});return function(events){return[];};}
return filterEvents(events,function(event){var eventId=parseEventId(event);return athleteData[athleteId].includes(eventId);});}
function createWithinFilter(withinStr){withinFilter=true;var distance,withinLatitude,withinLongitude;if(isNaN(withinStr)){var indexOf=withinStr.indexOf('-');distance=withinStr.substring(0,indexOf);var withinLongLat=withinStr.substring(indexOf+1).split(',');withinLatitude=withinLongLat[0];withinLongitude=withinLongLat[1];}else{distance=parseInt(withinStr);if(position===undefined){distance=0;withinLatitude=0;withinLongitude=0;}else{withinLatitude=position.coords.latitude;withinLongitude=position.coords.longitude;}}
addMarker(withinLatitude,withinLongitude,'Within '+distance+'km','orange');return filterEvents(events,function(event){var latitude=parseLatitude(event);var longitude=parseLongitude(event);return getDistanceFromLatLonInKm(latitude,longitude,withinLatitude,withinLongitude)<distance;});}
function createCompassFilter(){return function(events){var northern={},southern={},eastern={},western={};for(var e=0;e<events.length;e++){var event=events[e];var latitude=parseLatitude(event);var longitude=parseLongitude(event);if(isNaN(northern.latitude)||northern.latitude<latitude){northern={latitude:latitude,longitude:longitude,id:parseEventId(event),event:event};}
if(isNaN(eastern.longitude)||eastern.longitude<longitude){eastern={latitude:latitude,longitude:longitude,id:parseEventId(event),event:event};}
if(isNaN(southern.latitude)||southern.latitude>latitude){southern={latitude:latitude,longitude:longitude,id:parseEventId(event),event:event};}
if(isNaN(western.longitude)||western.longitude>longitude){western={latitude:latitude,longitude:longitude,id:parseEventId(event),event:event};}}
return _.uniq([northern.event,eastern.event,southern.event,western.event]);}}
function createClosestFilter(closestStr){closestFilter=true;var closest=closestStr;var closestLatitude,closestLongitude;if(isNaN(closest)){var indexOf=closest.indexOf('-');var closestLongLat=closest.substring(indexOf+1).split(',');closestLatitude=closestLongLat[0];closestLongitude=closestLongLat[1];closest=closest.substring(0,indexOf);}else{if(position===undefined){closest=0;closestLatitude=0;closestLongitude=0;}else{closest=parseInt(closestStr);closestLatitude=position.coords.latitude;closestLongitude=position.coords.longitude;}}
return function(events){var eventDistances=[];for(var e=0;e<events.length;e++){var event=events[e];var latitude=parseLatitude(event);var longitude=parseLongitude(event);var distance=getDistanceFromLatLonInKm(latitude,longitude,closestLatitude,closestLongitude);eventDistances.push({'event':event,'distance':distance});}
var closestEventDistances=eventDistances.sort(function(a,b){return a.distance-b.distance});var filteredEvents=[];if(eventDistances.length<closest){closest=eventDistances.length;}
addMarker(closestLatitude,closestLongitude,'Closest '+closest+' event ','green');for(var i=0;i<closest;i++){filteredEvents.push(eventDistances[i].event);}
return filteredEvents;}}
function createRandomFilter(){return function(events){var randomEvent=_.random(events.length-1);return[events[randomEvent]];}}
function createPinFilter(pinStr){var pin=pinStr;var indexOf=pin.indexOf('-');var pinColour=pin.substring(0,indexOf);var pinLongLat=pin.substring(indexOf+1).split(',');var pinLatitude=pinLongLat[0];var pinLongitude=pinLongLat[1];addMarker(pinLatitude,pinLongitude,'Pinned location',pinColour);return function(events){return events;};}
function getFilter(filter){if(filter.startsWith(FILTER_TYPES.SERIES_ID)){return createSeriesIdFilter(filter.substring(9));}else if(filter.startsWith(FILTER_TYPES.NOT)){return createNotFilter(filter.substring(4));}else if(filter.startsWith(FILTER_TYPES.AND)){return createAndFilter(filter.substring(4));}else if(filter.startsWith(FILTER_TYPES.OR)){return createOrFilter(filter.substring(3));}else if(filter.startsWith(FILTER_TYPES.STARTS_WITH)){return createStartsWithFilter(filter.substring(11));}else if(filter.startsWith(FILTER_TYPES.CONTAINS)){return createContainsFilter(filter.substring(9));}else if(filter.startsWith(FILTER_TYPES.MATCHES)){return createMatchesFilter(filter.substring(8));}else if(filter.startsWith(FILTER_TYPES.COUNTRY)){return createCountryFilter(filter.substring(8));}else if(filter.startsWith(FILTER_TYPES.ATHLETE)){return createAthleteFilter(filter.substring(8));}else if(filter.startsWith(FILTER_TYPES.WITHIN)){return createWithinFilter(filter.substring(7));}else if(filter==FILTER_TYPES.COMPASS){return createCompassFilter();}else if(filter.startsWith(FILTER_TYPES.CLOSEST)){return createClosestFilter(filter.substring(8));}else if(filter==FILTER_TYPES.RANDOM){return createRandomFilter();}else if(filter===FILTER_TYPES.NONE){return filterEvents(events,function(event){return[];});}else if(filter===FILTER_TYPES.ALL){return function(events){return events;};}else if(filter.startsWith(FILTER_TYPES.PIN)){return createPinFilter(filter.substring(4));}}
function getDistanceFromLatLonInKm(lat1,lon1,lat2,lon2){var R=6371;var dLat=deg2rad(lat2-lat1);var dLon=deg2rad(lon2-lon1);var a=Math.sin(dLat/2)*Math.sin(dLat/2)+
Math.cos(deg2rad(lat1))*Math.cos(deg2rad(lat2))*Math.sin(dLon/2)*Math.sin(dLon/2);var c=2*Math.atan2(Math.sqrt(a),Math.sqrt(1-a));return R*c;}
function deg2rad(deg){return deg*(Math.PI/180)}
function load(){$(document).ready(function(){markerGroup.clearLayers();var hash=decodeURIComponent(window.location.hash);filters=[];withinFilter=false;closestFilter=false;var h=0;hash.split('#').filter(function(e){return e}).forEach(function(hashPart){console.info('filter '+h+' '+hashPart);var filter=getFilter(hashPart);if(filter!==undefined){filters.push(filter);}
h++;});displayEvents(filters);});}
function init(){$(window).bind('hashchange',function(event){load();});$.ajax({url:EVENTS_API_URL,dataType:'json'}).done(function(data){$events=data.events;countries=data.countries;console.info('Events loaded: '+$events.features.length+' events');}).fail(function(jqXHR,textStatus,errorThrown){console.error('Failed to load events: '+textStatus+' '+errorThrown);noty({text:'Failed to load events. Please refresh the page.',type:'error'});});$('#letter-prefix').keypress(function(e){if(e.which==13){var prefix=$('#letter-prefix').val();var prefix=Array.from(new Set(prefix.toLowerCase().replace(/[^a-z]/ig,'').split(''))).join('');window.location.hash='#matches-^['+prefix+']';}});$('#search').keypress(function(e){if(e.which==13){var search=$('#search').val();window.location.hash='#matches-.*'+search+'.*';}});$('#athlete').keypress(function(e){if(e.which==13){var athlete=$('#athlete').val();window.location.hash='#athlete-'+athlete;}});}
function initAndLoad(){init();load();}